@dataclass
class JobMessage:
    message_id: str
    message_type: str
    payload: Dict[str, Any]
    receipt_handle: str
    timestamp: str = field(default_factory=lambda: datetime.utcnow().isoformat())
    retry_count: int = 0
    max_retries: int = 3

    @classmethod
    def from_sqs_message(cls, sqs_message: dict) -> 'JobMessage':
        body = json.loads(sqs_message['Body'])
        attributes = sqs_message.get('Attributes', {})
        return cls(
            message_id=sqs_message['MessageId'],
            message_type=body.get('type', 'unknown'),
            payload=body.get('payload', {}),
            receipt_handle=sqs_message['ReceiptHandle'],
            timestamp=body.get('timestamp', datetime.utcnow().isoformat()),
            retry_count=int(attributes.get('ApproximateReceiveCount', 1)) - 1,
            max_retries=body.get('max_retries', 3),
        )


