class HandlerRegistry:
    """Dynamic registry for message handlers."""

    def __init__(self):
        self._handlers: Dict[str, Type[MessageHandler]] = {}

    def register(self, message_type: str, handler_class: Type[MessageHandler]):
        """Register a handler for a specific message type."""
        if not issubclass(handler_class, MessageHandler):
            raise TypeError(f"{handler_class} must be a subclass of MessageHandler")
        self._handlers[message_type] = handler_class
        logger.info(f"Registered handler {handler_class.__name__} for message type '{message_type}'")

    def unregister(self, message_type: str):
        """Unregister a handler for a message type."""
        if message_type in self._handlers:
            del self._handlers[message_type]
            logger.info(f"Unregistered handler for message type '{message_type}'")

    def get_handler(self, message_type: str) -> Optional[MessageHandler]:
        """Get a handler instance for a message type."""
        handler_class = self._handlers.get(message_type)
        if handler_class:
            return handler_class()
        return None

    def get_registered_types(self):
        return list(self._handlers.keys())


class DeadLetterQueueManager:
    """Manages failed messages that exceed retry limits."""

    def __init__(self, sqs_client, dlq_url: Optional[str] = None):
        self.sqs_client = sqs_client
        self.dlq_url = dlq_url

    def send_to_dlq(self, message: JobMessage, error: str):
        if not self.dlq_url:
            logger.warning(f"No DLQ configured. Message {message.message_id} lost after max retries.")
            return

        try:
            dlq_body = {
                'original_message_id': message.message_id,
                'type': message.message_type,
                'payload': message.payload,
                'error': str(error),
                'retry_count': message.retry_count,
                'failed_at': datetime.utcnow().isoformat(),
            }
            self.sqs_client.send_message(
                QueueUrl=self.dlq_url,
                MessageBody=json.dumps(dlq_body),
                MessageAttributes={
                    'OriginalMessageType': {
                        'DataType': 'String',
                        'StringValue': message.message_type,
                    },
                    'FailureReason': {
                        'DataType': 'String',
                        'StringValue': str(error)[:256],
                    }
                }
            )
            logger.info(f"Message {message.message_id} sent to DLQ")
        except ClientError as e:
            logger.error(f"Failed to send message to DLQ: {e}")


class SQSWorker:
    """Main worker that polls SQS and dispatches messages to handlers."""

    def __init__(
        self,
        queue_url: str,
        region_name: str = 'us-east-1',
        max_messages: int = 10,
        wait_time_seconds: int = 20,
        visibility_timeout: int = 300,
        dlq_url: Optional[str] = None,
        aws_access_key_id: Optional[str] = None,
        aws_secret_access_key: Optional[str] = None,
        endpoint_url: Optional[str] = None,
    ):
        self.queue_url = queue_url
        self.max_messages = max_messages
        self.wait_time_seconds = wait_time_seconds
        self.visibility_timeout = visibility_timeout
        self._running = False

        # Build boto3 client kwargs
        client_kwargs = {'region_name': region_name}
        if aws_access_key_id and aws_secret_access_key:
            client_kwargs['aws_access_key_id'] = aws_access_key_id
            client_kwargs['aws_secret_access_key'] = aws_secret_access_key
        if endpoint_url:
            client_kwargs['endpoint_url'] = endpoint_url

        self.sqs_client = boto3.client('sqs', **client_kwargs)

        self.registry = HandlerRegistry()
        self.dlq_manager = DeadLetterQueueManager(self.sqs_client, dlq_url)

        # Stats tracking
        self.stats = {
            'messages_processed': 0,
            'messages_failed': 0,
            'messages_skipped': 0,
            'started_at': None,
        }

        # Register default handlers
        self._register_default_handlers()

    def _register_default_handlers(self):
        self.registry.register('email_notification', EmailNotificationHandler)
        self.registry.register('data_processing', DataProcessingHandler)
        self.registry.register('report_generation', ReportGenerationHandler)
        self.registry.register('webhook', WebhookHandler)
        self.registry.register('cleanup', CleanupHandler)

    def register_handler(self, message_type: str, handler_class: Type[MessageHandler]):
        """Register a custom message handler."""
        self.registry.register(message_type, handler_class)

    def _poll_messages(self):
        """Poll messages from SQS queue."""
        try:
            response = self.sqs_client.receive_message(
                QueueUrl=self.queue_url,
                MaxNumberOfMessages=self.max_messages,
                WaitTimeSeconds=self.wait_time_seconds,
                VisibilityTimeout=self.visibility_timeout,
                AttributeNames=['All'],
                MessageAttributeNames=['All'],
            )
            return response.get('Messages', [])
        except ClientError as e:
            logger.error(f"Error polling SQS: {e}")
            return []

    def _delete_message(self, receipt_handle: str):
        """Delete a successfully processed message from the queue."""
        try:
            self.sqs_client.delete_message(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle,
            )
        except ClientError as e:
            logger.error(f"Error deleting message: {e}")

    def _change_message_visibility(self, receipt_handle: str, timeout: int):
        """Change message visibility timeout for retry backoff."""
        try:
            self.sqs_client.change_message_visibility(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle,
                VisibilityTimeout=timeout,
            )
        except ClientError as e:
            logger.error(f"Error changing message visibility: {e}")

    def _process_message(self, sqs_message: dict):
        """Parse and dispatch a single SQS message."""
        try:
            message = JobMessage.from_sqs_message(sqs_message)
        except (json.JSONDecodeError, KeyError) as e:
            logger.error(f"Failed to parse message: {e}")
            # Delete malformed messages - they'll never succeed
            self._delete_message(sqs_message['ReceiptHandle'])
            self.stats['messages_skipped'] += 1
            return

        logger.info(
            f"Processing message {message.message_id} "
            f"(type={message.message_type}, retry={message.retry_count})"
        )

        handler = self.registry.get_handler(message.message_type)
        if handler is None:
            logger.warning(
                f"No handler registered for message type '{message.message_type}'. "
                f"Registered types: {self.registry.get_registered_types()}"
            )
            self.stats['messages_skipped'] += 1
            # Send unhandled message types to DLQ
            self.dlq_manager.send_to_dlq(message, f"No handler for type '{message.message_type}'")
            self._delete_message(message.receipt_handle)
            return

        try:
            success = handler.handle(message)

            if success:
                self._delete_message(message.receipt_handle)
                self.stats['messages_processed'] += 1
                logger.info(f"Message {message.message_id} processed successfully")
            else:
                self._handle_failure(message, "Handler returned False")

        except Exception as e:
            logger.exception(f"Error processing message {message.message_id}: {e}")
            self._handle_failure(message, str(e))

    def _handle_failure(self, message: JobMessage, error: str):
        """Handle a failed message - retry or send to DLQ."""
        self.stats['messages_failed'] += 1

        if message.retry_count >= message.max_retries:
            logger.error(
                f"Message {message.message_id} exceeded max retries ({message.max_retries}). "
                f"Sending to DLQ."
            )
            self.dlq_manager.send_to_dlq(message, error)
            self._delete_message(message.receipt_handle)
        else:
            # Exponential backoff for retries
            backoff_seconds = min(30 * (2 ** message.retry_count), 900)  # Max 15 minutes
            logger.warning(
                f"Message {message.message_id} failed (retry {message.retry_count}/{message.max_retries}). "
                f"Will retry in {backoff_seconds}s."
            )
            self._change_message_visibility(message.receipt_handle, backoff_seconds)

    def _log_stats(self):
        """Log current processing statistics."""
        logger.info(
            f"Worker stats - Processed: {self.stats['messages_processed']}, "
            f"Failed: {self.stats['messages_failed']}, "
            f"Skipped: {self.stats['messages_skipped']}"
        )

    def start(self):
        """Start the worker polling loop."""
        self._running = True
        self.stats['started_at'] = datetime.utcnow().isoformat()

        logger.info(f"SQS Worker started. Polling queue: {self.queue_url}")
        logger.info(f"Registered handlers: {self.registry.get_registered_types()}")

        poll_count = 0

        while self._running:
            try:
                messages = self._poll_messages()

                if messages:
                    logger.info(f"Received {len(messages)} message(s)")
                    for sqs_message in messages:
                        if not self._running:
                            break
                        self._process_message(sqs_message)

                poll_count += 1
                if poll_count % 10 == 0:
                    self._log_stats()

            except KeyboardInterrupt:
                logger.info("Received keyboard interrupt")
                self.stop()
            except Exception as e:
                logger.exception(f"Unexpected error in polling loop: {e}")
                time.sleep(5)  # Back off on unexpected errors

        logger.info("SQS Worker stopped.")
        self._log_stats()

    def stop(self):
        """Gracefully stop the worker."""
        logger.info("Stopping SQS Worker...")
        self._running = False


