def main():
    import argparse

    parser = argparse.ArgumentParser(description='SQS Worker - Asynchronous Job Processing System')
    parser.add_argument('--queue-url', required=True, help='SQS queue URL')
    parser.add_argument('--dlq-url', default=None, help='Dead letter queue URL')
    parser.add_argument('--region', default='us-east-1', help='AWS region')
    parser.add_argument('--max-messages', type=int, default=10, help='Max messages per poll')
    parser.add_argument('--wait-time', type=int, default=20, help='Long poll wait time in seconds')
    parser.add_argument('--visibility-timeout', type=int, default=300, help='Message visibility timeout')
    parser.add_argument('--endpoint-url', default=None, help='Custom endpoint URL (for LocalStack, etc.)')
    parser.add_argument('--send-test', action='store_true', help='Send test messages to the queue')

    args = parser.parse_args()

    worker = SQSWorker(
        queue_url=args.queue_url,
        region_name=args.region,
        max_messages=args.max_messages,
        wait_time_seconds=args.wait_time,
        visibility_timeout=args.visibility_timeout,
        dlq_url=args.dlq_url,
        endpoint_url=args.endpoint_url,
    )

    # Setup graceful shutdown
    def signal_handler(signum, frame):
        logger.info(f"Received signal {signum}")
        worker.stop()

    signal.signal(signal.SIGTERM, signal_handler)
    signal.signal(signal.SIGINT, signal_handler)

    if args.send_test:
        send_test_messages(args.queue_url, worker.sqs_client)

    worker.start()


if __name__ == '__main__':
    main()